import re

def count_politicians(articles, politician_names):
    # Create a set of politician names for quick lookup
    politician_set = set(politician_names)

    # Initialize a dictionary to store counts
    counts = {}

    # Process each article
    for article in articles:
        # Use regular expression to find all names in the article
        names = re.findall(r'\b(?:\w+\.?\w*)\b', article)

        # Check if the name is in the politician set
        for name in names:
            if name in politician_set:
                # Convert to lowercase for case-insensitive comparison
                lower_name = name.lower()
                if lower_name in counts:
                    counts[lower_name] += 1
                else:
                    counts[lower_name] = 1

    return counts
